const fs = require('node:fs');
const path = require('node:path');

const rootDir = path.resolve(__dirname, '..');
const modelPath = path.join(rootDir, 'models', 'warrior.glb');
const outputPath = path.join(rootDir, 'js', 'warrior-model.js');

const modelBase64 = fs.readFileSync(modelPath).toString('base64');
const modelDataUrl = `data:model/gltf-binary;base64,${modelBase64}`;

const output = [
  '// Generated by scripts/generate-warrior-model.js.',
  '// Update models/warrior.glb, then rerun `node scripts/generate-warrior-model.js`.',
  `window.WARRIOR_GLB_DATA_URL = ${JSON.stringify(modelDataUrl)};`,
  '',
].join('\n');

fs.writeFileSync(outputPath, output, 'utf8');
